import pytest

def test_message_timestamp_at_epoch_zero_boundary(auth_session, provider_id, api_base_url, cleanup_messages):
    base_payload = {"provider_id": provider_id, "subject": "BVA ts", "body": "Boundary check."}

    # Lower-bound valid: epoch zero
    payload_zero = {**base_payload, "client_timestamp": 0}
    resp_zero = auth_session.post(f"{api_base_url}/messages", json=payload_zero)
    assert resp_zero.status_code in (201, 422), \
        f"Epoch-0 timestamp: unexpected status {resp_zero.status_code}"
    if resp_zero.status_code == 201:
        cleanup_messages.append(resp_zero.json()["message_id"])
    else:
        assert resp_zero.json().get("error_code") == "TIMESTAMP_TOO_OLD"

    # Below lower-bound: negative timestamp
    payload_neg = {**base_payload, "client_timestamp": -1}
    resp_neg = auth_session.post(f"{api_base_url}/messages", json=payload_neg)
    assert resp_neg.status_code == 400, \
        f"Negative timestamp: expected 400, got {resp_neg.status_code}"
    assert resp_neg.json().get("error_code") == "INVALID_TIMESTAMP", \
        f"Unexpected error_code: {resp_neg.json().get('error_code')}"
